"Bladder Cancer Diagnosis" AS (
SELECT * FROM (SELECT patient_id, resource FROM "Condition: Bladder Cancer for Urology Care (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Bladder Cancer for Urology Care (qicore-condition-encounter-diagnosis)") AS BladderCancer WHERE CAST(intervalStart(CASE WHEN fhirpath_text(BladderCancer.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(BladderCancer.resource, 'onsetDateTime'), fhirpath_text(BladderCancer.resource, 'onsetPeriod.start'), fhirpath_text(BladderCancer.resource, 'recordedDate')), fhirpath_text(BladderCancer.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(BladderCancer.resource, 'onsetDateTime'), fhirpath_text(BladderCancer.resource, 'onsetPeriod.start'), fhirpath_text(BladderCancer.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(BladderCancer.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(BladderCancer.resource, 'onsetDateTime'), fhirpath_text(BladderCancer.resource, 'onsetPeriod.start'), fhirpath_text(BladderCancer.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(BladderCancer.resource, 'onsetDateTime'), fhirpath_text(BladderCancer.resource, 'onsetPeriod.start'), fhirpath_text(BladderCancer.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS TIMESTAMP) < CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS DATE) AND (fhirpath_bool(BladderCancer.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(BladderCancer.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(BladderCancer.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(BladderCancer.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()')
),
"Denominator Exception" AS (
SELECT p.patient_id FROM _patients AS p WHERE FALSE
),
"First Bladder Cancer Staging Procedure" AS (
SELECT p.patient_id, (SELECT resource FROM "Procedure: Tumor staging (tumor staging)" AS BladderCancerStaging WHERE BladderCancerStaging.status = 'completed' AND EXISTS (SELECT 1 FROM (SELECT * FROM "Bladder Cancer Diagnosis") AS BladderCancer WHERE CAST(intervalStart(CASE WHEN fhirpath_text(BladderCancerStaging.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(BladderCancerStaging.resource, 'performed')), '{') THEN fhirpath_text(BladderCancerStaging.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(BladderCancerStaging.resource, 'performed'), fhirpath_text(BladderCancerStaging.resource, 'performed'), TRUE, TRUE) END) AS DATE) <= CAST(intervalStart(CASE WHEN fhirpath_text(BladderCancer.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(BladderCancer.resource, 'onsetDateTime'), fhirpath_text(BladderCancer.resource, 'onsetPeriod.start'), fhirpath_text(BladderCancer.resource, 'recordedDate')), fhirpath_text(BladderCancer.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(BladderCancer.resource, 'onsetDateTime'), fhirpath_text(BladderCancer.resource, 'onsetPeriod.start'), fhirpath_text(BladderCancer.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(BladderCancer.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(BladderCancer.resource, 'onsetDateTime'), fhirpath_text(BladderCancer.resource, 'onsetPeriod.start'), fhirpath_text(BladderCancer.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(BladderCancer.resource, 'onsetDateTime'), fhirpath_text(BladderCancer.resource, 'onsetPeriod.start'), fhirpath_text(BladderCancer.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE) AND BladderCancer.patient_id = BladderCancerStaging.patient_id) AND BladderCancerStaging.patient_id = p.patient_id ORDER BY intervalStart(CASE WHEN fhirpath_text(BladderCancerStaging.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(BladderCancerStaging.resource, 'performed')), '{') THEN fhirpath_text(BladderCancerStaging.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(BladderCancerStaging.resource, 'performed'), fhirpath_text(BladderCancerStaging.resource, 'performed'), TRUE, TRUE) END) ASC NULLS LAST, json_extract_string(BladderCancerStaging.resource, '$.id') ASC NULLS LAST LIMIT 1) AS resource FROM _patients AS p
),
"Acute Tuberculosis Diagnosis" AS (
SELECT * FROM (SELECT patient_id, resource FROM "Condition: Tuberculosis for Urology Care (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Tuberculosis for Urology Care (qicore-condition-encounter-diagnosis)") AS ActiveTuberculosis WHERE (fhirpath_bool(ActiveTuberculosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(ActiveTuberculosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(ActiveTuberculosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(ActiveTuberculosis.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()') AND EXISTS (SELECT 1 FROM (SELECT * FROM "First Bladder Cancer Staging Procedure") AS FirstBladderCancerStaging WHERE intervalOverlaps(CASE WHEN fhirpath_text(ActiveTuberculosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(ActiveTuberculosis.resource, 'onsetDateTime'), fhirpath_text(ActiveTuberculosis.resource, 'onsetPeriod.start'), fhirpath_text(ActiveTuberculosis.resource, 'recordedDate')), fhirpath_text(ActiveTuberculosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(ActiveTuberculosis.resource, 'onsetDateTime'), fhirpath_text(ActiveTuberculosis.resource, 'onsetPeriod.start'), fhirpath_text(ActiveTuberculosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(ActiveTuberculosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(ActiveTuberculosis.resource, 'onsetDateTime'), fhirpath_text(ActiveTuberculosis.resource, 'onsetPeriod.start'), fhirpath_text(ActiveTuberculosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(ActiveTuberculosis.resource, 'onsetDateTime'), fhirpath_text(ActiveTuberculosis.resource, 'onsetPeriod.start'), fhirpath_text(ActiveTuberculosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END, CASE WHEN fhirpath_text(FirstBladderCancerStaging.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(FirstBladderCancerStaging.resource, 'performed')), '{') THEN fhirpath_text(FirstBladderCancerStaging.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(FirstBladderCancerStaging.resource, 'performed'), fhirpath_text(FirstBladderCancerStaging.resource, 'performed'), TRUE, TRUE) END) AND COALESCE(CAST(intervalEnd(CASE WHEN fhirpath_text(ActiveTuberculosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(ActiveTuberculosis.resource, 'onsetDateTime'), fhirpath_text(ActiveTuberculosis.resource, 'onsetPeriod.start'), fhirpath_text(ActiveTuberculosis.resource, 'recordedDate')), fhirpath_text(ActiveTuberculosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(ActiveTuberculosis.resource, 'onsetDateTime'), fhirpath_text(ActiveTuberculosis.resource, 'onsetPeriod.start'), fhirpath_text(ActiveTuberculosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(ActiveTuberculosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(ActiveTuberculosis.resource, 'onsetDateTime'), fhirpath_text(ActiveTuberculosis.resource, 'onsetPeriod.start'), fhirpath_text(ActiveTuberculosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(ActiveTuberculosis.resource, 'onsetDateTime'), fhirpath_text(ActiveTuberculosis.resource, 'onsetPeriod.start'), fhirpath_text(ActiveTuberculosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE), CAST('9999-12-31' AS DATE)) > COALESCE(CAST(intervalEnd(CASE WHEN fhirpath_text(FirstBladderCancerStaging.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(FirstBladderCancerStaging.resource, 'performed')), '{') THEN fhirpath_text(FirstBladderCancerStaging.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(FirstBladderCancerStaging.resource, 'performed'), fhirpath_text(FirstBladderCancerStaging.resource, 'performed'), TRUE, TRUE) END) AS DATE), CAST('9999-12-31' AS DATE)) AND FirstBladderCancerStaging.patient_id = ActiveTuberculosis.patient_id)
),
"BCG Not Available Within 6 Months After Bladder Cancer Staging" AS (
SELECT * FROM "MedicationAdministration: Bacillus Calmette Guerin for Urology Care (medicationadministrationnotdone)" AS BCGNotGiven WHERE in_valueset(BCGNotGiven.resource, 'statusReason', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1248.369') AND EXISTS (SELECT 1 FROM (SELECT * FROM "First Bladder Cancer Staging Procedure") AS FirstBladderCancerStaging WHERE CAST(intervalStart(CASE WHEN fhirpath_text(FirstBladderCancerStaging.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(FirstBladderCancerStaging.resource, 'performed')), '{') THEN fhirpath_text(FirstBladderCancerStaging.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(FirstBladderCancerStaging.resource, 'performed'), fhirpath_text(FirstBladderCancerStaging.resource, 'performed'), TRUE, TRUE) END) AS DATE) < CAST(fhirpath_text(BCGNotGiven.resource, 'extension.where(url=''http://hl7.org/fhir/us/qicore/StructureDefinition/qicore-recorded'').valueDateTime') AS DATE) AND CAST(fhirpath_text(BCGNotGiven.resource, 'extension.where(url=''http://hl7.org/fhir/us/qicore/StructureDefinition/qicore-recorded'').valueDateTime') AS DATE) <= CAST(intervalStart(CASE WHEN fhirpath_text(FirstBladderCancerStaging.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(FirstBladderCancerStaging.resource, 'performed')), '{') THEN fhirpath_text(FirstBladderCancerStaging.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(FirstBladderCancerStaging.resource, 'performed'), fhirpath_text(FirstBladderCancerStaging.resource, 'performed'), TRUE, TRUE) END) AS DATE) + INTERVAL '6 month' AND FirstBladderCancerStaging.patient_id = BCGNotGiven.patient_id)
),
"Cystectomy Done" AS (
SELECT * FROM "Procedure: Cystectomy for Urology Care" AS Cystectomy WHERE Cystectomy.status = 'completed' AND EXISTS (SELECT 1 FROM (SELECT * FROM "First Bladder Cancer Staging Procedure") AS FirstBladderCancerStaging WHERE CAST(intervalStart(CASE WHEN fhirpath_text(FirstBladderCancerStaging.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(FirstBladderCancerStaging.resource, 'performed')), '{') THEN fhirpath_text(FirstBladderCancerStaging.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(FirstBladderCancerStaging.resource, 'performed'), fhirpath_text(FirstBladderCancerStaging.resource, 'performed'), TRUE, TRUE) END) AS DATE) - INTERVAL '6 month' <= CAST(intervalStart(CASE WHEN fhirpath_text(Cystectomy.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(Cystectomy.resource, 'performed')), '{') THEN fhirpath_text(Cystectomy.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(Cystectomy.resource, 'performed'), fhirpath_text(Cystectomy.resource, 'performed'), TRUE, TRUE) END) AS DATE) AND CAST(intervalStart(CASE WHEN fhirpath_text(Cystectomy.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(Cystectomy.resource, 'performed')), '{') THEN fhirpath_text(Cystectomy.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(Cystectomy.resource, 'performed'), fhirpath_text(Cystectomy.resource, 'performed'), TRUE, TRUE) END) AS DATE) < CAST(intervalStart(CASE WHEN fhirpath_text(FirstBladderCancerStaging.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(FirstBladderCancerStaging.resource, 'performed')), '{') THEN fhirpath_text(FirstBladderCancerStaging.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(FirstBladderCancerStaging.resource, 'performed'), fhirpath_text(FirstBladderCancerStaging.resource, 'performed'), TRUE, TRUE) END) AS DATE) AND FirstBladderCancerStaging.patient_id = Cystectomy.patient_id)
),
"First BCG Administered" AS (
SELECT p.patient_id, (SELECT resource FROM "MedicationAdministration: Bacillus Calmette Guerin for Urology Care" AS BCG WHERE array_contains(['in-progress', 'completed'], fhirpath_text(BCG.resource, 'status')) AND EXISTS (SELECT 1 FROM (SELECT * FROM "First Bladder Cancer Staging Procedure") AS FirstBladderCancerStaging WHERE CAST(CAST(intervalStart(CASE WHEN fhirpath_text(FirstBladderCancerStaging.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(FirstBladderCancerStaging.resource, 'performed')), '{') THEN fhirpath_text(FirstBladderCancerStaging.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(FirstBladderCancerStaging.resource, 'performed'), fhirpath_text(FirstBladderCancerStaging.resource, 'performed'), TRUE, TRUE) END) AS DATE) AS DATE) < CAST(intervalStart(CASE WHEN fhirpath_text(BCG.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(BCG.resource, 'effective')), '{') THEN fhirpath_text(BCG.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(BCG.resource, 'effective'), fhirpath_text(BCG.resource, 'effective'), TRUE, TRUE) END) AS DATE) AND CAST(intervalStart(CASE WHEN fhirpath_text(BCG.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(BCG.resource, 'effective')), '{') THEN fhirpath_text(BCG.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(BCG.resource, 'effective'), fhirpath_text(BCG.resource, 'effective'), TRUE, TRUE) END) AS DATE) <= CAST(CAST(intervalStart(CASE WHEN fhirpath_text(FirstBladderCancerStaging.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(FirstBladderCancerStaging.resource, 'performed')), '{') THEN fhirpath_text(FirstBladderCancerStaging.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(FirstBladderCancerStaging.resource, 'performed'), fhirpath_text(FirstBladderCancerStaging.resource, 'performed'), TRUE, TRUE) END) AS DATE) + INTERVAL '6 month' AS DATE) AND intervalContains(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE), intervalStart(CASE WHEN fhirpath_text(BCG.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(BCG.resource, 'effective')), '{') THEN fhirpath_text(BCG.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(BCG.resource, 'effective'), fhirpath_text(BCG.resource, 'effective'), TRUE, TRUE) END)) AND FirstBladderCancerStaging.patient_id = BCG.patient_id) AND BCG.patient_id = p.patient_id ORDER BY intervalStart(CASE WHEN fhirpath_text(BCG.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(BCG.resource, 'effective')), '{') THEN fhirpath_text(BCG.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(BCG.resource, 'effective'), fhirpath_text(BCG.resource, 'effective'), TRUE, TRUE) END) ASC NULLS LAST, json_extract_string(BCG.resource, '$.id') ASC NULLS LAST LIMIT 1) AS resource FROM _patients AS p
),
"Has Excluding Chemotherapy or Radiotherapy Procedure Before Staging" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM ((SELECT patient_id, resource FROM "MedicationRequest: Chemotherapy Agents for Advanced Cancer" AS ExclusionMed WHERE array_contains(['active', 'completed'], fhirpath_text(ExclusionMed.resource, 'status')) AND fhirpath_text(ExclusionMed.resource, 'intent') = 'order' AND EXISTS (SELECT 1 FROM (SELECT * FROM "First Bladder Cancer Staging Procedure") AS FirstBladderCancerStaging WHERE CAST(intervalStart(CASE WHEN fhirpath_text(FirstBladderCancerStaging.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(FirstBladderCancerStaging.resource, 'performed')), '{') THEN fhirpath_text(FirstBladderCancerStaging.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(FirstBladderCancerStaging.resource, 'performed'), fhirpath_text(FirstBladderCancerStaging.resource, 'performed'), TRUE, TRUE) END) AS TIMESTAMP) - INTERVAL '6 month' <= CAST(intervalStart(list_extract(from_json(collapse_intervals(to_json(list_transform(from_json(fhirpath(ExclusionMed.resource, 'dosageInstruction.timing.repeat.bounds'), '["VARCHAR"]'), _lt_DoseTime -> CASE WHEN _lt_DoseTime IS NULL THEN NULL WHEN starts_with(LTRIM(_lt_DoseTime), '{') THEN _lt_DoseTime ELSE intervalFromBounds(CAST(_lt_DoseTime AS VARCHAR), CAST(_lt_DoseTime AS VARCHAR), TRUE, TRUE) END))), '["VARCHAR"]'), 1)) AS TIMESTAMP) AND CAST(intervalStart(list_extract(from_json(collapse_intervals(to_json(list_transform(from_json(fhirpath(ExclusionMed.resource, 'dosageInstruction.timing.repeat.bounds'), '["VARCHAR"]'), _lt_DoseTime -> CASE WHEN _lt_DoseTime IS NULL THEN NULL WHEN starts_with(LTRIM(_lt_DoseTime), '{') THEN _lt_DoseTime ELSE intervalFromBounds(CAST(_lt_DoseTime AS VARCHAR), CAST(_lt_DoseTime AS VARCHAR), TRUE, TRUE) END))), '["VARCHAR"]'), 1)) AS TIMESTAMP) < CAST(intervalStart(CASE WHEN fhirpath_text(FirstBladderCancerStaging.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(FirstBladderCancerStaging.resource, 'performed')), '{') THEN fhirpath_text(FirstBladderCancerStaging.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(FirstBladderCancerStaging.resource, 'performed'), fhirpath_text(FirstBladderCancerStaging.resource, 'performed'), TRUE, TRUE) END) AS TIMESTAMP) AND FirstBladderCancerStaging.patient_id = ExclusionMed.patient_id)) UNION (SELECT patient_id, resource FROM "Procedure: Combined radiotherapy (procedure)" AS ExclusionProcedure WHERE fhirpath_text(ExclusionProcedure.resource, 'status') = 'completed' AND EXISTS (SELECT 1 FROM (SELECT * FROM "First Bladder Cancer Staging Procedure") AS FirstBladderCancerStaging WHERE CAST(intervalStart(CASE WHEN fhirpath_text(FirstBladderCancerStaging.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(FirstBladderCancerStaging.resource, 'performed')), '{') THEN fhirpath_text(FirstBladderCancerStaging.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(FirstBladderCancerStaging.resource, 'performed'), fhirpath_text(FirstBladderCancerStaging.resource, 'performed'), TRUE, TRUE) END) AS TIMESTAMP) - INTERVAL '6 month' <= CAST(intervalStart(CASE WHEN fhirpath_text(ExclusionProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(ExclusionProcedure.resource, 'performed')), '{') THEN fhirpath_text(ExclusionProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(ExclusionProcedure.resource, 'performed'), fhirpath_text(ExclusionProcedure.resource, 'performed'), TRUE, TRUE) END) AS TIMESTAMP) AND CAST(intervalStart(CASE WHEN fhirpath_text(ExclusionProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(ExclusionProcedure.resource, 'performed')), '{') THEN fhirpath_text(ExclusionProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(ExclusionProcedure.resource, 'performed'), fhirpath_text(ExclusionProcedure.resource, 'performed'), TRUE, TRUE) END) AS TIMESTAMP) < CAST(intervalStart(CASE WHEN fhirpath_text(FirstBladderCancerStaging.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(FirstBladderCancerStaging.resource, 'performed')), '{') THEN fhirpath_text(FirstBladderCancerStaging.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(FirstBladderCancerStaging.resource, 'performed'), fhirpath_text(FirstBladderCancerStaging.resource, 'performed'), TRUE, TRUE) END) AS TIMESTAMP) AND FirstBladderCancerStaging.patient_id = ExclusionProcedure.patient_id))) AS _u WHERE _u.patient_id = p.patient_id)
),
"Has Excluding HIV, Immunocompromised Conditions or Mixed Histology Before Staging" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Condition: HIV (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: HIV (qicore-condition-encounter-diagnosis)" UNION SELECT patient_id, resource FROM "Condition: Immunocompromised Conditions (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Immunocompromised Conditions (qicore-condition-encounter-diagnosis)" UNION SELECT patient_id, resource FROM "Condition: Mixed Histology Urothelial Cell Carcinoma for Urology Care (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Mixed Histology Urothelial Cell Carcinoma for Urology Care (qicore-condition-encounter-diagnosis)") AS ExclusionDiagnosis WHERE ExclusionDiagnosis.patient_id = p.patient_id AND (fhirpath_bool(ExclusionDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(ExclusionDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(ExclusionDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(ExclusionDiagnosis.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()') AND EXISTS (SELECT 1 FROM (SELECT * FROM "First Bladder Cancer Staging Procedure") AS FirstBladderCancerStaging WHERE CAST(intervalStart(CASE WHEN fhirpath_text(ExclusionDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(ExclusionDiagnosis.resource, 'onsetDateTime'), fhirpath_text(ExclusionDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(ExclusionDiagnosis.resource, 'recordedDate')), fhirpath_text(ExclusionDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(ExclusionDiagnosis.resource, 'onsetDateTime'), fhirpath_text(ExclusionDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(ExclusionDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(ExclusionDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(ExclusionDiagnosis.resource, 'onsetDateTime'), fhirpath_text(ExclusionDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(ExclusionDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(ExclusionDiagnosis.resource, 'onsetDateTime'), fhirpath_text(ExclusionDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(ExclusionDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE) <= CAST(intervalStart(CASE WHEN fhirpath_text(FirstBladderCancerStaging.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(FirstBladderCancerStaging.resource, 'performed')), '{') THEN fhirpath_text(FirstBladderCancerStaging.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(FirstBladderCancerStaging.resource, 'performed'), fhirpath_text(FirstBladderCancerStaging.resource, 'performed'), TRUE, TRUE) END) AS DATE) AND FirstBladderCancerStaging.patient_id = ExclusionDiagnosis.patient_id))
),
"Has Qualifying Encounter" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM "Encounter: Office Visit" AS ValidEncounter WHERE ValidEncounter.patient_id = p.patient_id AND intervalIncludes(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE), fhirpath_text(ValidEncounter.resource, 'period')) AND NOT fhirpath_bool(ValidEncounter.resource, 'class.where(system=''http://terminology.hl7.org/CodeSystem/v3-ActCode'' and code=''VR'').exists()') AND fhirpath_text(ValidEncounter.resource, 'status') = 'finished')
),
"Immunosuppressive Drugs" AS (
SELECT * FROM "MedicationRequest: Immunosuppressive Drugs for Urology Care" AS ImmunosuppressiveDrugs WHERE array_contains(['active', 'completed'], ImmunosuppressiveDrugs.status) AND ImmunosuppressiveDrugs.intent = 'order' AND EXISTS (SELECT 1 FROM (SELECT * FROM "First Bladder Cancer Staging Procedure") AS FirstBladderCancerStaging WHERE CAST(intervalStart(COALESCE(CASE WHEN list_extract(list_sort(list_transform(from_json(fhirpath(ImmunosuppressiveDrugs.resource, 'dosageInstruction.timing'), '["VARCHAR"]'), _lt_dosageTiming -> fhirpath_text(_lt_dosageTiming, 'event')), 'asc'), 1) IS NULL THEN NULL WHEN starts_with(LTRIM(list_extract(list_sort(list_transform(from_json(fhirpath(ImmunosuppressiveDrugs.resource, 'dosageInstruction.timing'), '["VARCHAR"]'), _lt_dosageTiming -> fhirpath_text(_lt_dosageTiming, 'event')), 'asc'), 1)), '{') THEN list_extract(list_sort(list_transform(from_json(fhirpath(ImmunosuppressiveDrugs.resource, 'dosageInstruction.timing'), '["VARCHAR"]'), _lt_dosageTiming -> fhirpath_text(_lt_dosageTiming, 'event')), 'asc'), 1) ELSE intervalFromBounds(CAST(list_extract(list_sort(list_transform(from_json(fhirpath(ImmunosuppressiveDrugs.resource, 'dosageInstruction.timing'), '["VARCHAR"]'), _lt_dosageTiming -> fhirpath_text(_lt_dosageTiming, 'event')), 'asc'), 1) AS VARCHAR), CAST(list_extract(list_sort(list_transform(from_json(fhirpath(ImmunosuppressiveDrugs.resource, 'dosageInstruction.timing'), '["VARCHAR"]'), _lt_dosageTiming -> fhirpath_text(_lt_dosageTiming, 'event')), 'asc'), 1) AS VARCHAR), TRUE, TRUE) END, list_extract(from_json(collapse_intervals(to_json(list_transform(from_json(fhirpath(ImmunosuppressiveDrugs.resource, 'dosageInstruction.timing.repeat.bounds'), '["VARCHAR"]'), _lt_DoseTime -> CASE WHEN _lt_DoseTime IS NULL THEN NULL WHEN starts_with(LTRIM(_lt_DoseTime), '{') THEN _lt_DoseTime ELSE intervalFromBounds(CAST(_lt_DoseTime AS VARCHAR), CAST(_lt_DoseTime AS VARCHAR), TRUE, TRUE) END))), '["VARCHAR"]'), 1))) AS DATE) <= CAST(intervalStart(CASE WHEN fhirpath_text(FirstBladderCancerStaging.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(FirstBladderCancerStaging.resource, 'performed')), '{') THEN fhirpath_text(FirstBladderCancerStaging.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(FirstBladderCancerStaging.resource, 'performed'), fhirpath_text(FirstBladderCancerStaging.resource, 'performed'), TRUE, TRUE) END) AS DATE) AND FirstBladderCancerStaging.patient_id = ImmunosuppressiveDrugs.patient_id)
),
"Denominator Exclusion" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "Acute Tuberculosis Diagnosis" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Immunosuppressive Drugs" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Cystectomy Done" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Has Excluding HIV, Immunocompromised Conditions or Mixed Histology Before Staging" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Has Excluding Chemotherapy or Radiotherapy Procedure Before Staging" AS sub WHERE sub.patient_id = p.patient_id)
),
"July 1 of Year Prior to the Measurement Period" AS (
SELECT p.patient_id, (CAST(make_timestamp(Year(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) - INTERVAL '1 year'), 7, 1, 0, 0, CAST(0 AS DOUBLE) + CAST(0 AS DOUBLE) / 1000.0) AS VARCHAR) || printf('%+03.0f:00', CAST(0 AS DOUBLE))) AS value FROM _patients AS p
),
"June 30 of the Measurement Period" AS (
SELECT p.patient_id, (CAST(make_timestamp(Year(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP)), 6, 30, 23, 59, CAST(59 AS DOUBLE) + CAST(0 AS DOUBLE) / 1000.0) AS VARCHAR) || printf('%+03.0f:00', CAST(0 AS DOUBLE))) AS value FROM _patients AS p
),
"First Bladder Cancer Staging Procedure during 6 Months Prior to Measurement Period through the First 6 Months of Measurement Period" AS (
SELECT p.patient_id, (SELECT resource FROM "First Bladder Cancer Staging Procedure" AS FirstBladderCancerStaging WHERE CAST(intervalStart(CASE WHEN fhirpath_text(FirstBladderCancerStaging.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(FirstBladderCancerStaging.resource, 'performed')), '{') THEN fhirpath_text(FirstBladderCancerStaging.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(FirstBladderCancerStaging.resource, 'performed'), fhirpath_text(FirstBladderCancerStaging.resource, 'performed'), TRUE, TRUE) END) AS DATE) >= CAST((SELECT sub.value FROM "July 1 of Year Prior to the Measurement Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1) AS DATE) AND CAST(intervalEnd(CASE WHEN fhirpath_text(FirstBladderCancerStaging.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(FirstBladderCancerStaging.resource, 'performed')), '{') THEN fhirpath_text(FirstBladderCancerStaging.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(FirstBladderCancerStaging.resource, 'performed'), fhirpath_text(FirstBladderCancerStaging.resource, 'performed'), TRUE, TRUE) END) AS DATE) <= CAST((SELECT sub.value FROM "June 30 of the Measurement Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1) AS DATE) AND FirstBladderCancerStaging.patient_id = p.patient_id LIMIT 1) AS resource FROM _patients AS p
),
"Has Most Recent Bladder Cancer Tumor Staging is T1, Tis, Ta HG" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM "Observation" AS StagingObservation WHERE StagingObservation.patient_id = p.patient_id AND EXISTS (SELECT list((SELECT resource FROM "First Bladder Cancer Staging Procedure during 6 Months Prior to Measurement Period through the First 6 Months of Measurement Period" AS FirstBladderCancerStagingMP WHERE fhirpath_text(FirstBladderCancerStagingMP.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_StagingReference, 'reference'), '/'), -1))) FROM (SELECT unnest(from_json(fhirpath(StagingObservation.resource, 'partOf'), '["VARCHAR"]')) AS _lt_StagingReference) AS _lt_unnest) AND (fhirpath_bool(StagingObservation.resource, 'value.coding.where(system=''http://snomed.info/sct'' and code=''1228889001'').exists()') OR fhirpath_bool(StagingObservation.resource, 'value.coding.where(system=''http://snomed.info/sct'' and code=''1228884006'').exists()') OR fhirpath_bool(StagingObservation.resource, 'value.coding.where(system=''http://snomed.info/sct'' and code=''1228883000'').exists()') OR fhirpath_bool(StagingObservation.resource, 'value.coding.where(system=''http://hl7.org/fhir/sid/icd-10-cm'' and code=''D09.0'').exists()')) AND array_contains(['final', 'amended', 'corrected'], fhirpath_text(StagingObservation.resource, 'status')))
),
"Initial Population" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "Has Most Recent Bladder Cancer Tumor Staging is T1, Tis, Ta HG" AS sub WHERE sub.patient_id = p.patient_id) AND EXISTS (SELECT 1 FROM "Has Qualifying Encounter" AS sub WHERE sub.patient_id = p.patient_id)
),
"Denominator" AS (
SELECT * FROM "Initial Population"
),
"Numerator" AS (
SELECT p.patient_id FROM _patients AS p LEFT JOIN "First BCG Administered" AS j1 ON j1.patient_id = p.patient_id WHERE j1.resource IS NOT NULL
),
"SDE Ethnicity" AS (
SELECT * FROM "SDE.SDE Ethnicity"
),
"SDE Payer" AS (
SELECT * FROM "SDE.SDE Payer"
),
"SDE Race" AS (
SELECT * FROM "SDE.SDE Race"
),
"SDE Sex" AS (
SELECT * FROM "SDE.SDE Sex"
)
SELECT p.patient_id, (SELECT CASE WHEN "Initial Population".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS "Initial Population", (SELECT CASE WHEN "Denominator".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS Denominator, (SELECT CASE WHEN "Denominator Exclusion".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS "Denominator Exclusion", (SELECT CASE WHEN "Denominator Exception".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS "Denominator Exception", (SELECT CASE WHEN "Numerator".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS Numerator FROM _patients p LEFT JOIN "Initial Population" ON p.patient_id = "Initial Population".patient_id LEFT JOIN "Denominator" ON p.patient_id = "Denominator".patient_id LEFT JOIN "Denominator Exclusion" ON p.patient_id = "Denominator Exclusion".patient_id LEFT JOIN "Denominator Exception" ON p.patient_id = "Denominator Exception".patient_id LEFT JOIN "Numerator" ON p.patient_id = "Numerator".patient_id ORDER BY p.patient_id ASC
